    check_rate_limit(api_key)

    body = request.get("body", {})
    address_fields = ["street", "city", "state", "postal_code", "country"]
    new_address = {field: body.get(field) for field in address_fields}

    for u in users:
        if u.get("user_id") == user["user_id"]:
            u["billing_address"] = new_address
            return {"message": "Billing address updated", "billing_address": new_address}

    raise ValueError("User not found")

